const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// Bounded JSON parsing (enable only if you accept bodies)
app.use(express.json({ limit: '10kb' }));

// Basic rate limit
