const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { z } = require('zod'); // or joi / express-validator

const app = express();

// --- Security middleware ---
app.use(helmet());                              // sets secure HTTP headers
app.use(express.json({ limit: '10kb' }));       // cap body size (DoS mitigation)
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic rate limit

// --- Routes ---
