  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example of validated route with async error propagation
const userIdSchema = z.coerce.number().int().positive();

app.get('/users/:id', async (req, res, next) => {
  try {
    const id = userIdSchema.parse(req.params.id);
    const user = await findUser(id); // hypothetical
    if (!user) return res.status(404).json({ error: 'Not found' });
    // Only expose non-sensitive fields
    res.json({ id: user.id, name: user.name });
  } catch (err) {
    if (err instanceof z.ZodError) {
      return res.status(400).json({ error: 'Invalid id' });
    }
    next(err);
  }
});

app.get('/users', (req, res) => {
  // Avoid leaking PII unless the caller is authenticated/authorized
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 handler ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// --- Centralized error handler (must have 4 args) ---
app.use((err, req, res, next) => {
  // Log full error server-side, return generic message to client
  console.error(err);
  res.status(err.status || 500).json({
    error: process.env.NODE_ENV === 'production'
      ? 'Internal server error'
      : err.message,
  });
});

// --- Startup & graceful shutdown ---
const port = Number(process.env.PORT) || 3000;
const server = app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});

for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => {
    console.log(`${sig} received, shutting down`);
    server.close(() => process.exit(0));
  });
}

process.on('unhandledRejection', (reason) => {
  console.error('Unhandled rejection:', reason);
});

module.exports = app;
```

---

## Key Takeaways

| Area | Fix |
|---|---|
| **Error handling** | Centralized `(err, req, res, next)` middleware; never expose stack traces in production; handle `unhandledRejection` and `SIGTERM`. |
| **Input validation** | Validate **every** `req.params`, `req.query`, and `req.body` with a schema library (Zod, Joi, express-validator). Reject unknown fields. |
| **Async safety** | Wrap async handlers in try/catch (or an `asyncHandler` helper) so rejections reach the error middleware. |
| **Security headers** | `helmet()` covers CSP, HSTS, X-Frame-Options, etc. |
| **DoS mitigation** | Body-size limit (`express.json({ limit })`), rate limiting, request timeouts. |
| **Least privilege in responses** | Don't return emails/PII on unauthenticated endpoints; shape responses to the minimum necessary. |
| **Configuration** | Use `process.env.PORT`; never hardcode secrets. Pair with `.env` + `dotenv` and a `.env.example`. |
| **Logging** | Use a real logger (pino/winston) with request IDs; avoid `console.log` in production. |
| **Auth** | `/users` should require authentication (e.g., JWT/session middleware) before returning any user data. |

