app.use((req, res) => res.status(404).json({ error: 'Not Found' }));

process.on('unhandledRejection', (reason) => { console.error(reason); });
process.on('uncaughtException',  (err)    => { console.error(err); process.exit(1); });

const server = app.listen(PORT, () => console.log(`Listening on ${PORT}`));
server.on('error', (err) => { console.error('Listen failed:', err); process.exit(1); });
```

## 2. Input Validation

The current routes don't take input, but as soon as they do (query params, path params, body), validation is required. Use a schema validator:

```js
const { z } = require('zod');

const UserIdSchema = z.object({ id: z.coerce.number().int().positive() });

app.get('/users/:id', (req, res, next) => {
  const parsed = UserIdSchema.safeParse(req.params);
  if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
  // ... lookup
});
```

Add `app.use(express.json({ limit: '100kb' }))` with an explicit size limit to prevent large-payload DoS when body parsing is added.

## 3. Security Best Practices

**Add standard hardening middleware:**
```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.disable('x-powered-by');                // hide Express fingerprint
app.use(helmet());                          // sets secure HTTP headers
app.use(cors({ origin: ALLOWED_ORIGINS })); // explicit allowlist, not '*'
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```

**Other recommendations:**
- **Secrets/config:** Move `3000` to `process.env.PORT` and validate env on startup (e.g., with `envalid`).
