  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

const UsersQuery = z.object({
  limit: z.coerce.number().int().min(1).max(100).optional(),
});

app.get('/users', (req, res, next) => {
  try {
    const { limit = 10 } = UsersQuery.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' }, // email stripped from default projection
      { id: 2, name: 'Bob' },
    ].slice(0, limit);
    res.json(users);
  } catch (err) {
    if (err instanceof z.ZodError) {
      return res.status(400).json({ error: 'Invalid query', details: err.issues });
    }
    next(err);
  }
});

// --- 404 + error handler ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log server-side, return generic message to client
  console.error({ msg: 'unhandled', err: err.message, stack: err.stack });
  res.status(500).json({ error: 'Internal server error' });
});

// --- Server lifecycle ---
const port = Number(process.env.PORT) || 3000;
const server = app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});

const shutdown = (signal) => {
  console.log(`${signal} received, shutting down`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref();
};
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));
process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandledRejection', reason });
});
process.on('uncaughtException', (err) => {
