app.use((req, res, next) => {
  res.status(404).json({ error: 'Not Found' });
});

// Error handler — must have 4 args for Express to recognize it
app.use((err, req, res, next) => {
  // Log full details server-side only
  console.error({ msg: err.message, stack: err.stack, path: req.path });
  // Never return err.message or err.stack to the client in production
  const status = err.status || 500;
  res.status(status).json({
    error: status === 500 ? 'Internal Server Error' : err.message,
  });
});

process.on('unhandledRejection', (reason) => {
  console.error('unhandledRejection', reason);
});
process.on('uncaughtException', (err) => {
  console.error('uncaughtException', err);
  process.exit(1); // let a process supervisor restart
});
```

## 2. No input validation

**Problem:** Neither route accepts input today, but as soon as routes take params/bodies/queries they need strict validation. Set this up now.

**Fix:** Enable `express.json()` with a size limit, and add schema validation (`zod`, `joi`, or `express-validator`).

```js
