const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// JSON parser with a strict size limit
app.use(express.json({ limit: '10kb' }));

// Rate limiting (100 req/15min per IP)
app.use(rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// Disable the Express fingerprint header
app.disable('x-powered-by');

app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example: validate params with a whitelist pattern
app.get('/users/:id', (req, res, next) => {
  const id = Number(req.params.id);
  if (!Number.isInteger(id) || id <= 0) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  // ... lookup
  res.json({ id, name: 'Alice' });
});

app.get('/users', (req, res) => {
  // TODO: require auth; do not return emails unauthenticated
  res.json([{ id: 1, name: 'Alice' }, { id: 2, name: 'Bob' }]);
});

// 404 handler
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// Central error handler — never leak stack traces
app.use((err, req, res, _next) => {
  console.error({ err: err.message, stack: err.stack, path: req.path });
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

const PORT = Number(process.env.PORT) || 3000;
const server = app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

// Graceful shutdown
for (const sig of ['SIGTERM', 'SIGINT']) {
  process.on(sig, () => {
    server.close(() => process.exit(0));
    setTimeout(() => process.exit(1), 10_000).unref();
  });
}

module.exports = app;
```

