## Suggested Rewrite

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { z } = require('zod');

const app = express();

// --- Security & hardening ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example of validated input with zod
const UserIdSchema = z.object({
  id: z.coerce.number().int().positive().max(1_000_000),
});

app.get('/users/:id', (req, res, next) => {
  const parsed = UserIdSchema.safeParse(req.params);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  try {
    // ... lookup user by parsed.data.id
    res.json({ id: parsed.data.id, name: 'Alice' });
  } catch (err) {
    next(err);
  }
});

app.get('/users', (_req, res) => {
  // Consider requiring auth here; do not expose emails publicly.
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

// --- 404 + error middleware ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

app.use((err, _req, res, _next) => {
  // Log internally, never leak stack traces to clients.
  console.error(err);
  res.status(500).json({ error: 'Internal server error' });
});

