const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { z } = require('zod');

const app = express();

// --- Security middleware ---
app.use(helmet());
app.use(express.json({ limit: '10kb' }));           // cap body size
app.disable('x-powered-by');

app.use(rateLimit({
  windowMs: 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

// Example validated route (pattern to follow for future endpoints)
const userQuerySchema = z.object({
  limit: z.coerce.number().int().min(1).max(100).default(10),
});

app.get('/users', (req, res, next) => {
  try {
    const { limit } = userQuerySchema.parse(req.query);
    const users = [
      { id: 1, name: 'Alice' },  // email removed — PII minimization
      { id: 2, name: 'Bob' },
    ].slice(0, limit);
    res.json(users);
  } catch (err) {
    next(err);
  }
});

// --- 404 handler ---
app.use((req, res) => {
  res.status(404).json({ error: 'Not found' });
});

// --- Central error handler ---
// eslint-disable-next-line no-unused-vars
app.use((err, req, res, _next) => {
  // Don't leak stack traces
  const isValidation = err?.name === 'ZodError';
  const status = isValidation ? 400 : 500;
  const message = isValidation ? 'Invalid input' : 'Internal server error';

  // Log internally, return sanitized response
  console.error({ err: err.message, stack: err.stack });
  res.status(status).json({ error: message });
});

// --- Process-level safety ---
process.on('unhandledRejection', (reason) => {
  console.error('unhandledRejection:', reason);
});
process.on('uncaughtException', (err) => {
  console.error('uncaughtException:', err);
  process.exit(1);   // fail fast; let the orchestrator restart
});

// --- Graceful shutdown ---
const port = process.env.PORT || 3000;
const server = app.listen(port, () => {
  console.log(`Server running on port ${port}`);
});

const shutdown = (signal) => {
  console.log(`${signal} received, closing server...`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10000).unref();  // hard cutoff
};
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT', () => shutdown('SIGINT'));

module.exports = app;
```

---

## Summary of Changes

| Concern | Mitigation |
|---|---|
| Stack trace leaks | Central error handler returns generic messages; logs internally |
| DoS via large bodies | `express.json({ limit: '10kb' })` |
| Header-based attacks | `helmet()`, `x-powered-by` disabled |
| Brute force / abuse | `express-rate-limit` |
| Unvalidated input | `zod` schema per route — fail-closed with 400 |
| PII leakage | Removed email from `/users` response |
| Crash on async errors | `unhandledRejection` / `uncaughtException` handlers |
| Dropped in-flight requests | SIGTERM/SIGINT graceful shutdown with 10s hard cutoff |
| Hardcoded port | `process.env.PORT` with fallback |

