## Current Issues

### 1. No global error-handling middleware
Unhandled errors thrown synchronously or in promises will leak stack traces to the client in development, and can crash the process in production.

### 2. No input validation
The endpoints don't currently accept input, but as soon as parameters or bodies are added (e.g., `/users/:id` or `POST /users`), there's no validation scaffolding in place.

### 3. Missing security-hardening middleware
No `helmet`, no rate limiting, no CORS policy, no body-size limits, no request logging.

### 4. `app.listen` is called at module load
Because the file also does `module.exports = app`, requiring it in tests will start a real listener on port 3000 — a side effect and potential port conflict.

### 5. No 404 handler
Unknown routes fall through to Express's default HTML error page, which exposes framework details.

### 6. PII exposure
`/users` returns emails unconditionally with no auth. Even in a demo, this sets a bad pattern.

### 7. No graceful shutdown
No handling of `SIGTERM`/`SIGINT` or `uncaughtException`/`unhandledRejection`.

---

## Suggested Refactor

```js
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { param, validationResult } = require('express-validator');

const app = express();

// --- Security & hardening middleware ---
app.disable('x-powered-by');
app.use(helmet());
app.use(express.json({ limit: '10kb' }));           // cap body size
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic DoS guard

// --- Validation helper ---
const validate = (req, res, next) => {
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({ errors: errors.array() });
  }
  next();
};

// --- Routes ---
app.get('/health', (_req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

app.get('/users', (_req, res) => {
  // Don't leak PII by default; require auth in real code.
  res.json([
    { id: 1, name: 'Alice' },
    { id: 2, name: 'Bob' },
  ]);
});

app.get(
  '/users/:id',
  [param('id').isInt({ min: 1 }).toInt()],
  validate,
  (req, res) => {
    // req.params.id is now a validated integer
    res.json({ id: req.params.id });
  }
);

// --- 404 handler ---
app.use((_req, res) => res.status(404).json({ error: 'Not found' }));

// --- Global error handler (must be last, 4 args) ---
// eslint-disable-next-line no-unused-vars
app.use((err, _req, res, _next) => {
  // Log server-side; never send stack traces to clients.
  console.error(err);
  res.status(err.status || 500).json({ error: 'Internal server error' });
});

// --- Start only when run directly, not when required ---
if (require.main === module) {
  const server = app.listen(3000, () => {
    console.log('Server running on port 3000');
  });

  const shutdown = (signal) => {
    console.log(`${signal} received, shutting down`);
    server.close(() => process.exit(0));
    // Force-exit if shutdown hangs
    setTimeout(() => process.exit(1), 10_000).unref();
  };
  process.on('SIGTERM', () => shutdown('SIGTERM'));
  process.on('SIGINT', () => shutdown('SIGINT'));
  process.on('unhandledRejection', (reason) => { throw reason; });
  process.on('uncaughtException', (err) => {
    console.error('uncaughtException', err);
    process.exit(1);
  });
}

module.exports = app;
```

---

