const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const { param, validationResult } = require('express-validator');

const app = express();

// --- Security hardening ---
app.disable('x-powered-by');                              // (8)
app.use(helmet());                                        // (2)
app.use(express.json({ limit: '10kb' }));                 // (4) cap body size
app.use(rateLimit({                                       // (3)
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
}));

// --- Routes ---
app.get('/health', (req, res) => {
  res.json({ status: 'ok', timestamp: new Date().toISOString() });
});

const USERS = [
  { id: 1, name: 'Alice', email: 'alice@example.com' },
  { id: 2, name: 'Bob',   email: 'bob@example.com' },
];

app.get('/users', (req, res, next) => {
  try {
    res.json(USERS);
  } catch (err) {
    next(err);
  }
});

// Example of a validated, parameterized endpoint pattern to extend from (4)
app.get(
  '/users/:id',
  param('id').isInt({ min: 1, max: 2_147_483_647 }).toInt(),
  (req, res, next) => {
    const errors = validationResult(req);
    if (!errors.isEmpty()) {
      return res.status(400).json({ error: 'Invalid id' });   // no echo of user input
    }
    const user = USERS.find(u => u.id === req.params.id);
    if (!user) return res.status(404).json({ error: 'Not found' });
    res.json(user);
  }
);

// --- 404 + centralized error handler (1) ---
app.use((req, res) => res.status(404).json({ error: 'Not found' }));

// eslint-disable-next-line no-unused-vars
app.use((err, req, res, _next) => {
  // Log server-side with correlation info; never leak err.stack to the client
  console.error({ msg: 'unhandled_error', path: req.path, err: err.message });
  res.status(500).json({ error: 'Internal Server Error' });
});

// --- Config + graceful shutdown (5,6,7) ---
const PORT = Number(process.env.PORT) || 3000;
const HOST = process.env.HOST || '127.0.0.1';

const server = app.listen(PORT, HOST, () => {
  console.log(`Server running on http://${HOST}:${PORT}`);
});

function shutdown(signal) {
  console.log(`${signal} received, shutting down`);
  server.close(() => process.exit(0));
  setTimeout(() => process.exit(1), 10_000).unref(); // force-exit fallback
}
process.on('SIGTERM', () => shutdown('SIGTERM'));
process.on('SIGINT',  () => shutdown('SIGINT'));

process.on('unhandledRejection', (reason) => {
  console.error({ msg: 'unhandled_rejection', reason: String(reason) });
});
process.on('uncaughtException', (err) => {
  console.error({ msg: 'uncaught_exception', err: err.message });
  shutdown('uncaughtException');
});

module.exports = app;
```

